// src/routes/undian.ts
var undianRoute = new Hono2();
undianRoute.use("*", jwtAuth);
undianRoute.get("/:id/winners", async (c) => {
  const groupId = c.req.param("id");
  const [{ data }, { data: group }] = await Promise.all([
    supabase.from("winners").select("id, user_id, created_at, period_id, periods(periode_ke), users(name, phone)").eq("group_id", groupId).order("created_at", { ascending: false }),
    supabase.from("groups").select("nominal, jumlah_periode").eq("id", groupId).single()
  ]);
  const arisanAmount = group ? group.nominal * group.jumlah_periode : 0;
  const winners = (data ?? []).map((w) => ({ ...w, arisan_amount: arisanAmount }));
  return c.json({ winners });
});
var undianSchema = external_exports.discriminatedUnion("mode", [
  external_exports.object({ mode: external_exports.literal("fixed"), period_id: external_exports.string().uuid() }),
  external_exports.object({ mode: external_exports.literal("random"), period_id: external_exports.string().uuid() }),
  external_exports.object({
    mode: external_exports.literal("manual"),
    period_id: external_exports.string().uuid(),
    winner_id: external_exports.string().uuid()
  })
]);
undianRoute.post("/:id/undian", zValidator("json", undianSchema), async (c) => {
  const ketuaId = c.get("userId");
  const groupId = c.req.param("id");
  const body = c.req.valid("json");
  const { data: group } = await supabase.from("groups").select("ketua_id, name, mode_undian").eq("id", groupId).single();
  if (!group) return c.json({ error: "Grup tidak ditemukan" }, 404);
  if (group.ketua_id !== ketuaId)
    return c.json({ error: "Hanya ketua yang bisa melakukan undian" }, 403);
  if (body.mode !== group.mode_undian)
    return c.json(
      { error: `Mode undian tidak sesuai. Grup ini menggunakan mode "${group.mode_undian}".` },
      400
    );
  const { data: period } = await supabase.from("periods").select("id, periode_ke, status").eq("id", body.period_id).eq("group_id", groupId).single();
  if (!period) return c.json({ error: "Periode tidak ditemukan" }, 404);
  if (period.status !== "active") return c.json({ error: "Periode tidak aktif" }, 400);
  const { data: existingWinner } = await supabase.from("winners").select("id").eq("period_id", body.period_id).eq("group_id", groupId).single();
  if (existingWinner) return c.json({ error: "Undian untuk periode ini sudah dilakukan" }, 400);
  let winnerId = null;
  let winnerName = "";
  if (body.mode === "fixed") {
    const member = await undianFixed(groupId, period.periode_ke);
    if (!member) return c.json({ error: "Tidak ada anggota dengan urutan ini" }, 400);
    winnerId = member.user_id;
    winnerName = member.name;
  } else if (body.mode === "random") {
    winnerId = await undianRandom(groupId);
    if (!winnerId)
      return c.json({ error: "Tidak ada anggota yang memenuhi syarat untuk undian" }, 400);
    const { data: winnerUser } = await supabase.from("users").select("name, phone").eq("id", winnerId).single();
    winnerName = winnerUser?.name || winnerUser?.phone || "anggota";
  } else {
    const { data: manualUser } = await supabase.from("users").select("name").eq("id", body.winner_id).single();
    if (!manualUser) return c.json({ error: "User pemenang tidak ditemukan" }, 404);
    const { data: isMember } = await supabase.from("group_members").select("id").eq("group_id", groupId).eq("user_id", body.winner_id).single();
    if (!isMember) return c.json({ error: "User bukan anggota grup ini" }, 400);
    const result = await undianManual(body.winner_id);
    winnerId = result.user_id;
    winnerName = manualUser.name;
  }
  await saveWinner(groupId, body.period_id, winnerId);
  await broadcastUndianResult(groupId, winnerName, period.periode_ke);
  await logActivity(groupId, ketuaId, "undian", `Undian mode ${body.mode}: pemenang ${winnerName}`);
  void (async () => {
    const { data: members } = await supabase.from("group_members").select("user_id").eq("group_id", groupId);
    if (!members) return;
    for (const m of members) {
      const isWinner = m.user_id === winnerId;
      await insertNotification(
        m.user_id,
        "undian_done",
        isWinner ? "Kamu Menang Undian!" : "Undian Selesai",
        isWinner ? `Selamat! Kamu adalah pemenang undian periode ${period.periode_ke} di grup ${group.name}.` : `Undian periode ${period.periode_ke} di grup ${group.name} selesai. Pemenang: ${winnerName}.`,
        { group_id: groupId, period_id: body.period_id, winner_id: winnerId }
      ).catch(() => {
      });
    }
  })();
  return c.json({
    winner: { id: winnerId, name: winnerName },
    periode_ke: period.periode_ke
  });
});

// src/services/swaps.ts
async function getUserSwapCount(userId, groupId) {
  const { count } = await supabase.from("swap_requests").select("*", { count: "exact", head: true }).eq("requester_id", userId).eq("group_id", groupId).eq("status", "approved");
  return count ?? 0;
}
async function createSwapRequest(requesterId, targetId, groupId) {
  const swapCount = await getUserSwapCount(requesterId, groupId);
  if (swapCount >= 2) {
    return { error: "Kamu sudah menggunakan jatah tukar giliran maksimal (2x) di grup ini" };
  }
  const { data: pending } = await supabase.from("swap_requests").select("id").eq("requester_id", requesterId).eq("group_id", groupId).eq("status", "pending").maybeSingle();
  if (pending) {
    return { error: "Kamu masih punya permintaan tukar giliran yang belum selesai di grup ini" };
  }
  const { data: requesterMember } = await supabase.from("group_members").select("urutan").eq("group_id", groupId).eq("user_id", requesterId).single();
  if (!requesterMember) return { error: "Kamu bukan anggota grup ini" };
  const { data: requesterPeriod } = await supabase.from("periods").select("id").eq("group_id", groupId).eq("periode_ke", requesterMember.urutan).eq("status", "completed").maybeSingle();
  if (requesterPeriod) {
    return { error: "Giliran kamu sudah berlangsung, tidak bisa ditukar lagi" };
  }
  const { data: targetMember } = await supabase.from("group_members").select("urutan").eq("group_id", groupId).eq("user_id", targetId).single();
  if (!targetMember) return { error: "User target bukan anggota grup ini" };
  const { data: targetPeriod } = await supabase.from("periods").select("id").eq("group_id", groupId).eq("periode_ke", targetMember.urutan).eq("status", "completed").maybeSingle();
  if (targetPeriod) {
    return { error: "Giliran target sudah berlangsung, tidak bisa ditukar" };
  }
  const { data: swap, error: error51 } = await supabase.from("swap_requests").insert({ group_id: groupId, requester_id: requesterId, target_id: targetId }).select().single();
  if (error51 || !swap) return { error: "Gagal membuat permintaan tukar giliran" };
  await sendWA(targetId, `Ada permintaan tukar giliran arisan untukmu. Buka aplikasi untuk merespons.`);
  insertNotification(
    targetId,
    "swap_request",
    "Permintaan Tukar Giliran",
    "Ada anggota yang ingin menukar giliran arisan dengan kamu. Buka aplikasi untuk merespons.",
    { group_id: groupId, swap_id: swap.id }
  ).catch(() => {
  });
  return { swap };
}
async function respondSwap(swapId, targetId, response) {
  const { data: swap } = await supabase.from("swap_requests").select("*").eq("id", swapId).single();
  if (!swap) return { error: "Permintaan tukar giliran tidak ditemukan" };
  if (swap.target_id !== targetId) return { error: "Kamu bukan target dari permintaan ini" };
  if (swap.status !== "pending" && swap.status !== "ketua_pending") {
    return { error: "Permintaan ini sudah tidak bisa direspons" };
  }
  if (response === "rejected") {
    await supabase.from("swap_requests").update({ status: "rejected", target_response_at: /* @__PURE__ */ new Date() }).eq("id", swapId);
    await sendWA(swap.requester_id, `Permintaan tukar giliran kamu ditolak.`);
    return { status: "rejected" };
  }
  if (swap.status === "ketua_pending") {
    const { error: updateErr } = await supabase.from("swap_requests").update({ status: "approved", target_response_at: /* @__PURE__ */ new Date(), ketua_response_at: /* @__PURE__ */ new Date() }).eq("id", swapId);
    if (updateErr) return { error: "Gagal memperbarui permintaan tukar giliran" };
    const { data: requesterMember } = await supabase.from("group_members").select("urutan").eq("group_id", swap.group_id).eq("user_id", swap.requester_id).single();
    const { data: targetMember } = await supabase.from("group_members").select("urutan").eq("group_id", swap.group_id).eq("user_id", swap.target_id).single();
    if (requesterMember && targetMember) {
      await supabase.from("group_members").update({ urutan: targetMember.urutan }).eq("group_id", swap.group_id).eq("user_id", swap.requester_id);
      await supabase.from("group_members").update({ urutan: requesterMember.urutan }).eq("group_id", swap.group_id).eq("user_id", swap.target_id);
      await logActivity(
        swap.group_id,
        swap.requester_id,
        "swap_approved",
        `Tukar giliran (inisiatif ketua) disetujui: urutan ${requesterMember.urutan} \u2194 ${targetMember.urutan}`
      );
    }
    await sendWA(swap.requester_id, `Tukar giliran kamu disetujui! Urutan kamu telah diperbarui.`);
    const { data: grp } = await supabase.from("groups").select("ketua_id").eq("id", swap.group_id).single();
    if (grp?.ketua_id)
      await sendWA(
        grp.ketua_id,
        `Tukar giliran yang kamu inisiasi telah disetujui oleh anggota target.`
      );
    return { status: "approved" };
  }
  const { error: error51 } = await supabase.from("swap_requests").update({ status: "waiting_ketua", target_response_at: /* @__PURE__ */ new Date() }).eq("id", swapId);
  if (error51) return { error: "Gagal memperbarui permintaan tukar giliran" };
  const { data: group } = await supabase.from("groups").select("ketua_id").eq("id", swap.group_id).single();
  if (group?.ketua_id) {
    await sendWA(
      group.ketua_id,
      `Ada permintaan tukar giliran di grup arisan yang menunggu persetujuanmu. Buka aplikasi untuk menyetujui.`
    );
  }
  return { status: "waiting_ketua" };
}
async function createKetuaSwapRequest(ketuaId, memberAId, memberBId, groupId) {
  if (memberAId === memberBId) return { error: "Pilih dua anggota yang berbeda" };
  const { data: group } = await supabase.from("groups").select("ketua_id").eq("id", groupId).single();
  if (!group) return { error: "Grup tidak ditemukan" };
  if (group.ketua_id !== ketuaId)
    return { error: "Hanya ketua yang bisa menginisiasi tukar giliran ini" };
  for (const memberId of [memberAId, memberBId]) {
    const { data: member } = await supabase.from("group_members").select("urutan").eq("group_id", groupId).eq("user_id", memberId).single();
    if (!member) return { error: "Salah satu anggota bukan member grup ini" };
    const { data: completedPeriod } = await supabase.from("periods").select("id").eq("group_id", groupId).eq("periode_ke", member.urutan).eq("status", "completed").maybeSingle();
    if (completedPeriod)
      return { error: "Salah satu anggota sudah melewati gilirannya, tidak bisa ditukar" };
  }
  const { data: existingSwap } = await supabase.from("swap_requests").select("id").eq("group_id", groupId).or(
    `and(requester_id.eq.${memberAId},target_id.eq.${memberBId}),and(requester_id.eq.${memberBId},target_id.eq.${memberAId})`
  ).in("status", ["pending", "ketua_pending", "waiting_ketua"]).maybeSingle();
  if (existingSwap)
    return {
      error: "Sudah ada permintaan tukar giliran yang sedang diproses antara dua anggota ini"
    };
  const { data: swap, error: error51 } = await supabase.from("swap_requests").insert({
    group_id: groupId,
    requester_id: memberAId,
    target_id: memberBId,
    status: "ketua_pending"
  }).select().single();
  if (error51 || !swap) return { error: "Gagal membuat permintaan tukar giliran" };
  await sendWA(
    memberBId,
    `Ketua grup arisan mengajukan tukar giliran antara kamu dan anggota lain. Buka aplikasi untuk merespons.`
  );
  return { swap };
}
async function approveSwap(swapId, ketuaId, decision) {
  const { data: swap } = await supabase.from("swap_requests").select("*").eq("id", swapId).single();
  if (!swap) return { error: "Permintaan tukar giliran tidak ditemukan" };
  if (swap.status !== "waiting_ketua") return { error: "Permintaan ini sudah tidak bisa diproses" };
  const { data: group } = await supabase.from("groups").select("ketua_id").eq("id", swap.group_id).single();
  if (!group || group.ketua_id !== ketuaId) {
    return { error: "Hanya ketua grup yang bisa menyetujui tukar giliran" };
  }
  const { error: error51 } = await supabase.from("swap_requests").update({ status: decision, ketua_response_at: /* @__PURE__ */ new Date() }).eq("id", swapId);
  if (error51) return { error: "Gagal memperbarui status tukar giliran" };
  if (decision === "approved") {
    const { data: requesterMember } = await supabase.from("group_members").select("urutan").eq("group_id", swap.group_id).eq("user_id", swap.requester_id).single();
    const { data: targetMember } = await supabase.from("group_members").select("urutan").eq("group_id", swap.group_id).eq("user_id", swap.target_id).single();
    if (requesterMember && targetMember) {
      await supabase.from("group_members").update({ urutan: targetMember.urutan }).eq("group_id", swap.group_id).eq("user_id", swap.requester_id);
      await supabase.from("group_members").update({ urutan: requesterMember.urutan }).eq("group_id", swap.group_id).eq("user_id", swap.target_id);
      await logActivity(
        swap.group_id,
        ketuaId,
        "swap_approved",
        `Tukar giliran disetujui: urutan ${requesterMember.urutan} \u2194 ${targetMember.urutan}`
      );
    }
    await sendWA(
      swap.requester_id,
      `Permintaan tukar giliran kamu disetujui oleh ketua. Giliran kamu telah diperbarui.`
    );
  } else {
    await sendWA(swap.requester_id, `Permintaan tukar giliran kamu ditolak oleh ketua.`);
  }
  return { status: decision };
}

