swapsRoute.post(
  "/",
  zValidator(
    "json",
    external_exports.object({
      target_id: external_exports.string().uuid(),
      group_id: external_exports.string().uuid()
    })
  ),
  async (c) => {
    const requesterId = c.get("userId");
    const { target_id, group_id } = c.req.valid("json");
    if (requesterId === target_id)
      return c.json({ error: "Kamu tidak bisa menukar giliran dengan dirimu sendiri" }, 400);
    const { data: targetWin } = await supabase.from("winners").select("id").eq("group_id", group_id).eq("user_id", target_id).limit(1).maybeSingle();
    if (targetWin)
      return c.json(
        {
          error: "Target sudah pernah memenangkan undian dan menerima uang arisan. Tidak bisa tukar giliran dengan penerima arisan."
        },
        400
      );
    const { data: requesterWin } = await supabase.from("winners").select("id").eq("group_id", group_id).eq("user_id", requesterId).limit(1).maybeSingle();
    if (requesterWin)
      return c.json(
        {
          error: "Kamu sudah pernah memenangkan undian. Tukar giliran hanya untuk anggota yang belum mendapat giliran."
        },
        400
      );
    const result = await createSwapRequest(requesterId, target_id, group_id);
    if (result.error) return c.json({ error: result.error }, 400);
    return c.json({ swap: result.swap }, 201);
  }
);
