swapsRoute.post(
  "/:id/approve",
  zValidator("json", external_exports.object({ decision: external_exports.enum(["approved", "ketua_rejected"]) })),
  async (c) => {
    const ketuaId = c.get("userId");
    const swapId = c.req.param("id");
    const { decision } = c.req.valid("json");
    const result = await approveSwap(swapId, ketuaId, decision);
    if (result.error) return c.json({ error: result.error }, 400);
    void (async () => {
      const { data: swap } = await supabase.from("swap_requests").select("requester_id, target_id, group_id").eq("id", swapId).single();
      if (!swap) return;
      const approved = decision === "approved";
      await insertNotification(
        swap.requester_id,
        "swap_approved",
        approved ? "Tukar Giliran Disetujui" : "Tukar Giliran Ditolak",
        approved ? "Ketua menyetujui request tukar giliran kamu." : "Ketua menolak request tukar giliran kamu.",
        { group_id: swap.group_id, swap_id: swapId }
      ).catch(() => {
      });
      if (approved) {
        await insertNotification(
          swap.target_id,
          "swap_approved",
          "Tukar Giliran Disetujui",
          "Ketua menyetujui tukar giliran kamu dengan anggota lain.",
          { group_id: swap.group_id, swap_id: swapId }
        ).catch(() => {
        });
      }
    })();
    return c.json({ status: result.status });
  }
);

