notificationsRoute.get("/", async (c) => {
  const userId = c.get("userId");
  const limit = Math.min(parseInt(c.req.query("limit") ?? "20"), 50);
  const before = c.req.query("before");
  let query = supabase.from("notifications").select("id, type, title, body, data, is_read, created_at", { count: "exact" }).eq("user_id", userId).order("created_at", { ascending: false }).limit(limit + 1);
  if (before) {
    const { data: pivot } = await supabase.from("notifications").select("created_at").eq("id", before).single();
    if (pivot) query = query.lt("created_at", pivot.created_at);
  }
  const { data, error: error51 } = await query;
  if (error51) return c.json({ error: "Gagal memuat notifikasi" }, 500);
  const rows = data ?? [];
  const has_more = rows.length > limit;
  const notifications = has_more ? rows.slice(0, limit) : rows;
  const { count } = await supabase.from("notifications").select("id", { count: "exact", head: true }).eq("user_id", userId).eq("is_read", false);
  return c.json({ notifications, unread_count: count ?? 0, has_more });
});
